import { Question } from "./mathQuestions";

export interface TestModule {
  id: string;
  title: string;
  section: "reading-writing" | "math";
  difficulty: "easy" | "medium" | "hard";
  timeMinutes: number;
  questions: Question[];
}

export interface FullTest {
  id: string;
  title: string;
  modules: TestModule[];
}

const q = (testNum: number, mod: string, num: number): string => `t${testNum}-${mod}-q${num}`;

// ─── TEST 1: Reading & Writing Module 1 (27 questions) ───
// Order: Craft & Structure (Q1-7) → Information & Ideas (Q8-14) → Standard English Conventions (Q15-21) → Expression of Ideas (Q22-27)

const t1rw1: Question[] = [
  // ── Craft & Structure (1-7): Words in Context + Text Structure/Purpose ──
  { id: q(1,"rw1",1), text: "Ghost Dance, written by playwright and Otoe-Missouria Tribe member Annette Arkeketa, gets its title from a ceremony performed in the late 1800s by Native American peoples as an act of resistance against the US government. The play tells of a corporate lawyer who returns home, reconnects with her family, and uses her legal ______ to help her tribe.\n\nWhich choice completes the text with the most logical and precise word or phrase?", options: ["proceedings", "incentives", "monopoly", "prowess"], correctIndex: 3, explanation: "'Prowess' means great skill or expertise—the lawyer uses her legal expertise to help her tribe." },
  { id: q(1,"rw1",2), text: "Hieroglyphs, the Ancient Egyptian writing system, utilized both letters and symbols and contained an estimated 1,000 characters. Before the discovery of the Rosetta Stone, an ancient stone slab containing a royal decree translated into three languages, these hieroglyphs had been largely ______; once the stone was analyzed, linguists could finally begin to understand the meaning of the mysterious symbols.\n\nWhich choice completes the text with the most logical and precise word or phrase?", options: ["completed", "incomprehensible", "significant", "responsible"], correctIndex: 1, explanation: "'Incomprehensible' means impossible to understand—before the Rosetta Stone, no one could decipher hieroglyphs." },
  { id: q(1,"rw1",3), text: "Publicly accessible satellite imagery such as Google Earth has enabled scientists to document cave walls that can be up to seven meters tall and are often in previously unknown locations. Some researchers theorize that desert livestock structures were used to contain wild animals, while some others propose that these structures were used to ______ either claim.\n\nWhich choice completes the text with the most logical and precise word or phrase?", options: ["invoke", "necessitate", "corroborate", "withdraw"], correctIndex: 2, explanation: "'Corroborate' means to confirm or support—the imagery could help confirm either theory." },
  { id: q(1,"rw1",4), text: "The following text is adapted from George Bernard Shaw's 1913 play Pygmalion.\nMRS. PEARCE: Well, sir, whatever you choose to call it, I beg you not to let the girl hear you repeat it.\nHIGGINS: Oh, very well, very well. Is that all?\nMRS. PEARCE: No, sir. We shall have to be very particular with this girl as to personal cleanliness.\n\nAs used in the text, what does the word 'slovenly' most nearly mean?", options: ["Unkempt", "Informal", "Sympathetic", "Tasteful"], correctIndex: 0, explanation: "'Slovenly' means messy, untidy, or unkempt—in context, Mrs. Pearce is discussing personal cleanliness." },
  { id: q(1,"rw1",5), text: "The following text is adapted from Anton Chekhov's short story 'The Lottery Ticket.' Ivan Dmitritch has a lottery ticket for which the winning number does not match. He sits in the garden, thinking of nothing, and feeling all over the sweet, not going to the office today, or the day after, or the next.\n\nWhich choice best characterizes the overall structure of the text?", options: ["It portrays a character falling asleep after eating and then describes this character waking up to go to work.", "It depicts a character considering how his life might change and then details specific future fantasies about this character's lifestyle.", "It explains a character's thoughts about winning the lottery and then describes this character's somber mood after not winning.", "It explains a character's inspiration for purchasing a lottery ticket and then highlights his family's excitement about potentially winning the lottery."], correctIndex: 2, explanation: "The text moves from the character's hopeful thoughts about winning to his disappointment after seeing the number doesn't match." },
  { id: q(1,"rw1",6), text: "The following text is an excerpt from the 1799 poem 'Pleasures of Hope' by Thomas Campbell.\nAs with bright arch, when heaven's ethereal bow\nSpans with bright arch the glittering hills below,\nWhy do those cliffs of shadowy tint appear\nMore sweet than all the landscape smiling near?\n\nWhich choice best states the main purpose of the text?", options: ["To question whether bright or dim lighting is more likely to make an individual commit a specific scene to memory", "To describe how private experiences with inanimate objects affect the way individuals present themselves in public settings", "To challenge the idea that people looking at natural scenes are more likely to experience depression than elation", "To show how a measure of separation can enhance the allure of something"], correctIndex: 3, explanation: "The poem asks why distant, shadowy cliffs appear more beautiful than nearby scenery—exploring how distance enhances beauty." },
  { id: q(1,"rw1",7), text: "The following text is from Emily Pauline Johnson's 1903 poem 'Fire-Flowers.'\nAnd only where the forest fires have sped,\nScorching relentlessly the cool north land,\n<u>A sweet wild flower lifts its purple head,</u>\nAnd, like some gentle spirit, sorrow-fed,\nIt hides the scars with almost human hands.\n\nWhich choice best describes the function of the underlined portion in the text as a whole?", options: ["It draws a distinction between the forest's precariousness and the author's convictions.", "It describes the forest as foreboding and inhospitable.", "It reveals the author's detachment from the overwhelming forces of nature.", "It portrays the flower as having overcome adversity."], correctIndex: 3, explanation: "The flower lifts its head where fire has destroyed—it has overcome the adversity of the fire and now hides the scars." },

  // ── Information & Ideas (8-14): Main Idea, Evidence, Inferences ──
  { id: q(1,"rw1",8), text: "The following text is from Samuel Griswold Goodrich's 1836 poem 'Song: The Robin.'\nAt misty dawn,\nAt rosy morn,\nThe Redbreast sings alone:\nAt twilight dim,\nStill, still, his hymn\nHath a sad, and borrowing tone.\n\nWhich choice best states the main purpose of the text?", options: ["To demonstrate that the songs of birds vary extensively in tone and quality", "To highlight a bird's similar rituals even at different times of the day", "To convey that one may experience melancholy while alone but cheerfulness around others", "To present endearing reminiscences of a morning spent watching birds carefully"], correctIndex: 1, explanation: "The poem shows the robin singing at dawn, morning, and twilight—highlighting the bird's consistent ritual across different times." },
  { id: q(1,"rw1",9), text: "The end goal for many substance use disorder recovery programs is complete abstinence from alcohol and drugs. However, there is a growing trend toward multiple pathways to recovery. Some experts argue that abstinence-only recovery programs should also consider harm reduction, which focuses on reducing substance use, as a viable stepping stone to full abstinence. According to these experts, rigid abstinence-only programs fail to recognize that the best recovery plan is the one that works best for the specific individual in recovery.\n\nWhich choice best states the main idea of the text?", options: ["Individuals who have been in recovery for many years typically use several different recovery programs.", "Harm reduction strategies that encourage individuals to limit their use of substances have proven more effective than abstinence-based recovery strategies.", "Although harm reduction programs are controversial, some experts contend that reducing substance use can help people recover from substance use disorders.", "Some experts argue that the end goal of many substance use disorder recovery programs is suspect and problematic."], correctIndex: 2, explanation: "The passage presents harm reduction as a debated but potentially helpful approach to substance use disorder recovery." },
  { id: q(1,"rw1",10), text: "The following text is adapted from W. T. Nichols's 1916 novel The Safety First Club. Sam is a teenager.\nSam Parker stepped out upon the side porch of his father's house, closing the door behind him with a slam. He was, as a matter of fact, in a rather bad humor, which did not lessen as he surveyed the dull, grey sky, and saw its promise of a dismal day.\n\nWhich choice best states the main idea of the text?", options: ["Sam's bad mood worsens because of the prospect of poor weather.", "Sam slams the door because his father has upset him.", "Sam usually seeks fresh air as a means to improve his current mood.", "Sam responds to dreary weather in a matter-of-fact manner."], correctIndex: 0, explanation: "Sam is already in a bad mood, and seeing the grey sky and dismal weather makes it worse." },
  { id: q(1,"rw1",11), text: "A group of researchers investigated the effects of a novel environment compared with a familiar environment on memory recall across different age groups. They found that, although word recall varied greatly across age groups under novel environments, word recall was similar across age groups under familiar environments. Therefore, they concluded that while age groups may differ in memory recall, people perform better under familiar environments than novel environments.\n\nNumber of Words Recalled out of 30:\n• Ages 18-27: Novel 23, Familiar 25\n• Ages 28-38: Novel 21, Familiar 26\n• Ages 39-49: Novel 20, Familiar 23\n• Ages 50-60: Novel 18, Familiar 20\n• Over 60: Novel 15, Familiar 20\n\nWhich choice best describes data from the table that support the researchers' claim?", options: ["All five groups of participants had higher recall in the familiar environment, though the number of words recalled ranged from 20 to 26.", "Among the age groups in the table, the group that had the highest word recall in novel environments also had the highest word recall in familiar environments.", "Age groups 28-38 and 39-49 had approximately the same word recall in familiar environments, but ages 39-49 had a higher word recall in novel environments than did ages 28-38.", "Among the age groups in the table, those ages 39-49 and those over 60 had the lowest word recall in novel and familiar environments."], correctIndex: 0, explanation: "All groups performed better in familiar environments (higher recall), supporting the claim. The range of 20-26 in familiar vs lower in novel shows the pattern." },
  { id: q(1,"rw1",12), text: "To investigate the effect of different filtered lights on the growth rate of rose bushes, a student in a chemistry class placed seedling rose bushes in either a blue filtered light enclosure or a red filtered light enclosure and tracked the growth process over 45 days. The student concluded that the increased height of rose bushes was influenced solely by red light and that blue light was not responsible for any growth.\n\nWhich choice best describes data from the graph that weaken the student's conclusion?", options: ["The height of rose bushes under blue filtered light also substantially grew by day 45.", "The height of rose bushes was lower under blue filtered light than red filtered light on day 45.", "The largest increase in height of rose bushes under red filtered light occurred from day 15 to day 30.", "The height of rose bushes was the same in both light enclosures on day 1."], correctIndex: 0, explanation: "If rose bushes under blue light also grew substantially, this weakens the claim that blue light was 'not responsible for any growth.'" },
  { id: q(1,"rw1",13), text: "'The Rainy Day' is an 1842 poem by Henry Wadsworth Longfellow. In the poem, the speaker uses natural imagery to suggest that, despite his emotional struggles, there is still cause for hope, writing:\n\nWhich quotation from 'The Rainy Day' most effectively illustrates the claim?", options: ["'The day is cold, and dark, and dreary.'", "'The vine still clings to the mouldering wall.'", "'But the hopes of youth fall thick in the blast.'", "'Behind the clouds is the sun still shining.'"], correctIndex: 3, explanation: "'Behind the clouds is the sun still shining' uses natural imagery (sun behind clouds) to convey hope despite struggles." },
  { id: q(1,"rw1",14), text: "Although a key tenet in a physician-patient relationship is honesty, a survey showed that 50% of physicians regularly prescribe placebos, substances that have no medicinal effect. One possible explanation is that when creating a treatment plan, a physician may prescribe two or more medications for the patient to try. The patient will be informed that one of those medications is a placebo but will remain unaware as to which one, thus:\n\nWhich choice most logically completes the text?", options: ["encouraging more physicians to prescribe placebos as a standard form of treatment.", "hindering other instances of honesty in the typical physician-patient relationship.", "prompting patients to request placebo treatment in lieu of traditional treatment methods.", "maintaining honest communication in the physician-patient relationship."], correctIndex: 3, explanation: "Since the patient is told one medication is a placebo (even though they don't know which), honesty is maintained." },

  // ── Standard English Conventions (15-21): Grammar, Punctuation, Structure ──
  { id: q(1,"rw1",15), text: "Exploring abyssal plains on the deep ocean floor is difficult because of the vastness of the ______ vehicles capable of withstanding the water pressure to travel to depths of 3,000 to 6,000 meters.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["plains and the lack of", "plains, and the lack of,", "plains and, the lack of", "plains, and, the lack of"], correctIndex: 0, explanation: "No commas needed—'the vastness of the plains and the lack of vehicles' is a compound object of the preposition." },
  { id: q(1,"rw1",16), text: "The effects of the Industrial Revolution, which greatly increased the levels of air pollution in Great Britain, Europe, and the US, are not completely known due to the lack of exact data. Fortunately, since ______ painted during the Industrial Revolution, researchers can use the artists' depictions of the atmosphere to track changes in the effects of air pollution.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["artists Joseph Turner, and Claude Monet", "artists, Joseph Turner, and Claude Monet", "artists Joseph Turner and Claude Monet", "artists, Joseph Turner and Claude Monet,"], correctIndex: 2, explanation: "No commas needed between 'artists' and their names when the names are essential appositives." },
  { id: q(1,"rw1",17), text: "A team of researchers at Yunnan University assessed the performance of a hybrid of two rice ______ Oryza sativa, which is domesticated Asian rice, and Oryza longistaminata, which is undomesticated African rice.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["species:", "species;", "species,", "species—"], correctIndex: 0, explanation: "A colon introduces the specification/list of the two species." },
  { id: q(1,"rw1",18), text: "Chemehuevi photographer Cara Romero's work uses staging and digital tools to explore Indigenous life. In 2015, Romero utilized underwater photography to portray a moment from her tribe's ______ in 2017, Romero photographed Puebloan juxtaposed with TVs displaying traditional media depictions of Native Americans.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["history, then,", "history,", "history;", "history then,"], correctIndex: 2, explanation: "A semicolon separates two independent clauses about different years of Romero's work." },
  { id: q(1,"rw1",19), text: "When writing about Antiguan-American novelist Jamaica Kincaid, ______ have connected it to the colonial relationship between England and Antigua.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["the examination by literary critics has been of Kincaid's exploration of the mother-daughter bond; they", "there are literary critics who have examined Kincaid's exploration of the mother-daughter bond, and they", "Kincaid's exploration of the mother-daughter bond has been examined by literary critics, who", "literary critics have examined Kincaid's exploration of the mother-daughter bond and"], correctIndex: 3, explanation: "'Literary critics have examined...and have connected...' makes 'literary critics' the subject performing both actions without a dangling modifier." },
  { id: q(1,"rw1",20), text: "Terrol Dew Johnson, a Tohono O'odham sculptor, weaver, and advocate for Indigenous foods, helped create a nonprofit community development organization, Tohono O'odham Community Action, in 2013; and an art installation, 'Meeting the Clouds Halfway,' in 2016.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["Action, in 1996, a national publication,", "Action, in 1996; a national publication;", "Action; in 1996, a national publication,", "Action; in 1996, a national publication;"], correctIndex: 3, explanation: "Semicolons separate items in a complex list where items themselves contain commas." },
  { id: q(1,"rw1",21), text: "The films of Israeli cinematographer Yael Bartana often touch on historical themes, such as the intertwining elements of Jewish and Polish identities and the experiences of Ashkenazi Jews in Europe in the 19th and 20th centuries. ______ Bartana looks to the future: some of her more recent works represent fictional dystopian scenarios that allow audiences to analyze the role of women in politics.\n\nWhich choice completes the text with the most logical transition?", options: ["Therefore,", "For this reason,", "In fact,", "Still,"], correctIndex: 3, explanation: "'Still' signals a contrast—despite focusing on historical themes, Bartana also looks to the future." },

  // ── Expression of Ideas (22-27): Transitions + Rhetorical Synthesis (notes-based) ──
  { id: q(1,"rw1",22), text: "While researching a topic, a student has taken the following notes:\n• The US National Park Service (NPS) was established in 1916.\n• In 1956, the NPS set a goal, called Mission 66, to expand the numbers of visitors by its fiftieth anniversary.\n• The expansion of the US highway system and increased car ownership made remote places, like national parks, more accessible.\n• Mission 66 led to the building of more than 100 visitor centers in the parks.\n• NPS estimated that 80 million people would visit national parks in 1966, but the actual number was 127 million.\n\nThe student wants to emphasize the role infrastructure played in the achievement of a goal. Which choice most effectively uses relevant information from the notes to accomplish this goal?", options: ["Expanded highways, increased car ownership, and new visitor centers helped the National Park Service increase the number of visitors by 1966.", "In 1956, the National Park Service wanted to expand the number of visitors the parks would welcome in 1966.", "The National Park Service celebrated its fiftieth anniversary by expanding infrastructure during Mission 66.", "National parks in the US were visited by 127 million people in 1966, the fiftieth anniversary of the National Park Service."], correctIndex: 0, explanation: "Option A directly connects infrastructure improvements (highways, car ownership, visitor centers) to the achievement of the visitor goal." },
  { id: q(1,"rw1",23), text: "While researching a topic, a student has taken the following notes:\n• Vogelsang Pass is a mountain pass in California.\n• It is located in Yosemite National Park.\n• Its maximum elevation is 10,680 feet.\n• Stevens Pass is a mountain pass in Washington.\n• It is located in the Cascade Mountains.\n• Its maximum elevation is 4,061 feet.\n\nThe student wants to compare the elevations of the two mountain passes. Which choice most effectively uses relevant information from the notes to accomplish this goal?", options: ["Two examples of mountain passes in the US are the Vogelsang Pass in California and the Stevens Pass in Washington.", "The mountain pass in Yosemite National Park that has a maximum elevation of 10,680 feet is the Vogelsang Pass.", "Vogelsang Pass reaches a maximum elevation of 10,680 feet, while Stevens Pass reaches a maximum elevation of 4,061 feet.", "Some of the mountain passes in the US, including one mountain pass in Yosemite National Park in California, reach elevations of over 10,000 feet."], correctIndex: 2, explanation: "Option C directly compares both passes' elevations side by side." },
  { id: q(1,"rw1",24), text: "While researching a topic, a student has taken the following notes:\n• In 1876, German composer Richard Wagner debuted his epic music drama Der Ring des Nibelungen.\n• His lengthy opera, consisting of four parts and fifteen hours of music, is based on the epic poem Nibelungenlied and Norse legendary sagas.\n• In 1976, American composer Philip Glass debuted his opera Einstein on the Beach.\n• Glass's lengthy opera, lasting for five hours, has four parts and does not have a narrative arc.\n• Instead, it relies on repeated imagery and allusions to Albert Einstein's life and work.\n\nThe student wants to emphasize a similarity between the two works. Which choice most effectively uses relevant information from the notes to accomplish this goal?", options: ["Wagner's opera is based on an epic poem, while Glass's opera is based on a real person.", "Wagner's and Glass's operas are both lengthy, lasting fifteen and five hours, respectively.", "Although Wagner and Glass are both composers, their operas differ in their subject matter.", "German composer Wagner debuted his opera in 1876, and American composer Glass debuted his opera in 1976."], correctIndex: 1, explanation: "Option B highlights a similarity—both operas are notably lengthy—while providing specific details." },
  { id: q(1,"rw1",25), text: "While researching a topic, a student has taken the following notes:\n• A marsquake is a shaking that takes place on Mars's surface or in its interior, similar to an earthquake.\n• NASA sent Viking 2 to observe Mars's seismic activity in the 1970s.\n• In 2018, NASA sent the InSight Mars lander to Mars's surface.\n• It measured seismic activity and observed the first confirmed marsquake in 2019 in the canyon system Valles Marineris.\n\nThe student wants to specify the reason the InSight mission was sent to Mars. Which choice most effectively uses relevant information from the notes to accomplish this goal?", options: ["Marsquakes occur on Mars, but one wasn't observed until 2019 in Valles Marineris, by the InSight Mars lander.", "In 2018, the InSight Mars lander was sent to measure seismic activity on Mars and observed a marsquake a year later.", "Although NASA sent Viking 2 to Mars in the 1970s, a marsquake wasn't observed until 2019, by the InSight Mars lander.", "Viking 2 was sent to Mars in the 1970s to observe possible marsquakes, and the InSight Mars lander was sent in 2018."], correctIndex: 1, explanation: "Option B specifies InSight's purpose (to measure seismic activity) and includes the result." },
  { id: q(1,"rw1",26), text: "While researching a topic, a student has taken the following notes:\n• Cathy Park Hong is a writer and professor.\n• She writes about the experiences of marginalized people.\n• She also experiments with multiple languages.\n• Hong wrote her novel Dance Dance Revolution in 2007.\n• Her non-fiction book Minor Feelings was published in 2020.\n\nThe student wants to emphasize a difference between the two books. Which choice most effectively uses relevant information from the notes to accomplish this goal?", options: ["Dance Dance Revolution and Minor Feelings contain experiences of marginalized people and experiment with multiple languages.", "While Hong wrote both books, her 2007 work Dance Dance Revolution is a novel, and her 2020 work Minor Feelings is a non-fiction book.", "Hong has focused on the experiences of marginalized people in her writing, including the books Dance Dance Revolution and Minor Feelings.", "In the 2000s, Hong wrote two books, Dance Dance Revolution and Minor Feelings."], correctIndex: 1, explanation: "Option B emphasizes the key difference: one is a novel and the other is non-fiction." },
  { id: q(1,"rw1",27), text: "While researching a topic, a student has taken the following notes:\n• Bowhead whales once numbered between 25,000 and 100,000 individuals in the Greenland Sea and North Atlantic.\n• During the whaling era, they were hunted to near extinction, and now there are an estimated 300 individuals.\n• Researchers from the Greenland Institute and the University of Copenhagen recently spotted two calves in the Greenland Sea.\n• Only two other calves have been spotted over the past several years.\n• The observations suggest that the population of bowhead whales may be increasing.\n\nThe student wants to emphasize the recent sighting's significance. Which choice most effectively uses relevant information from the notes to accomplish this goal?", options: ["Researchers observed two bowhead whale calves, bringing the number up to four calf observations.", "After bowhead whales were nearly hunted to extinction during the whaling era, researchers have reason to believe that they may be increasing in number due to the rare sighting of two calves.", "The population of bowhead whales was estimated to be 300 individuals; two calves were recently observed in the Greenland Sea.", "Researchers observed bowhead whale calves in the Greenland Sea, where thousands of bowhead whales used to live."], correctIndex: 1, explanation: "Option B provides context (near extinction) that makes the calf sighting significant, emphasizing why this matters." },
];

// ─── TEST 1: Reading & Writing Module 2 (27 questions, harder) ───
const t1rw2: Question[] = [
  // ── Craft & Structure (1-7) ──
  { id: q(1,"rw2",1), text: "Benjamin Prud'homme and colleagues explored how convergent evolution—when the same trait evolves independently in separate lineages—can result from shared genetic mechanisms. Patricia Wittkopp investigated convergence through different genetic pathways. <u>Their combined work motivated Green and Extavour to evaluate both types.</u>\n\nThe underlined sentence primarily serves to:", options: ["Introduce a new research question", "Present a finding that contrasts with Prud'homme's work", "Explain why Green and Extavour conducted their study", "Summarize the conclusions of all three research teams"], correctIndex: 2, explanation: "The sentence explains the motivation—the gap between two approaches—that led Green and Extavour to their study." },
  { id: q(1,"rw2",2), text: "Despite its stated claims of global relevance, major research on income inequality in the 2010s suffered from a myopic focus on a few Western nations. Researchers would later ______ this shortcoming through access to administrative records in developing nations.\n\nWhich choice completes the text with the most logical and precise word?", options: ["postulate", "ameliorate", "sanction", "rationalize"], correctIndex: 1, explanation: "'Ameliorate' means to improve or remedy—addressing the shortcoming of limited geographic scope." },
  { id: q(1,"rw2",3), text: "In the 2010s, vintage G.I. Joe prices rose dramatically, which had the counterintuitive effect of ______ demand: new buyers entered the market expecting continued price increases.\n\nWhich choice completes the text with the most logical and precise word?", options: ["satisfying", "capitalizing", "exploiting", "eliciting"], correctIndex: 3, explanation: "'Eliciting' means drawing out or calling forth—the price rise drew out new demand." },
  { id: q(1,"rw2",4), text: "The fact that Ellen McGrattan's publications are frequently cited in other scholars' work ______ the usefulness of her research—other economists clearly find her studies valuable.\n\nWhich choice completes the text with the most logical and precise word?", options: ["forestalls", "belies", "underscores", "overshadows"], correctIndex: 2, explanation: "'Underscores' means emphasizes or highlights the usefulness." },
  { id: q(1,"rw2",5), text: "Fungal research by Cordero et al. found that certain mushrooms achieve hypothermic states through evaporative cooling, with <u>temperature reductions observed in surrounding air</u>. Though slight, these reductions inspired an air-cooling device.\n\nThe underlined observation serves to:", options: ["Establish a finding central to discussing a practical application", "Present a tangential finding about fungi", "Identify an unexpected observation that motivated the study", "Qualify an earlier claim about evaporative cooling"], correctIndex: 0, explanation: "The air-temperature reduction finding bridges the pure research to the practical application (cooling device)." },
  { id: q(1,"rw2",6), text: "In Algeria, solid fuel use fell by three-fourths between 2000 and 2019. The energy ladder model explains such shifts by appeal to income. However, Heltberg's study of Ghana shows fuel use was influenced by multiple factors including grid stability.\n\nThe Algeria information serves to:", options: ["Provide an example the energy ladder model explains well", "Introduce a finding explained equally well two ways", "Describe a trend with similar causes to one in Ghana", "Illustrate a phenomenon the text suggests is frequently but inadequately accounted for by the energy ladder model"], correctIndex: 3, explanation: "Algeria illustrates the type of fuel-use shift that the energy ladder attempts but fails to fully explain." },
  { id: q(1,"rw2",7), text: "Chelsea Wood et al. tracked temperature-driven changes in parasite abundance. Complex life cycle parasites (CLPs) decreased as temperatures rose, while directly transmitted parasites remained stable.\n\nThis finding most directly suggests:", options: ["CLPs are more affected by temperature than directly transmitted parasites", "Directly transmitted parasites benefit from warming", "All parasites decline with temperature increases", "Temperature has no meaningful effect on parasite populations"], correctIndex: 0, explanation: "CLP decline plus stability of others → CLPs are more vulnerable to temperature changes." },

  // ── Information & Ideas (8-14) ──
  { id: q(1,"rw2",8), text: "Nancy Bird-Walton was an aviation pioneer who undoubtedly accomplished much, but to gain a lasting place in historical memory, there is little that can ______ being the first. For example, people always remember that Aloha Wanderwell was the first woman to drive around the world.\n\nWhich choice completes the text with the most logical and precise word?", options: ["overreach by", "fluctuate with", "constrain within", "prevail over"], correctIndex: 3, explanation: "'Prevail over' means to surpass—nothing can overcome the power of being 'first' in public memory." },
  { id: q(1,"rw2",9), text: "A researcher conducted a meta-analysis of anthropogenic noise effects on animals. For every animal class examined, relevant behaviors differed significantly between noise-exposed and unexposed groups.\n\nThis finding most directly supports which claim?", options: ["Noise pollution is the greatest threat to wildlife globally", "Anthropogenic noise consistently affects animal behavior across diverse species", "All forms of noise are inherently harmful to animals", "Meta-analyses provide more reliable results than individual studies"], correctIndex: 1, explanation: "Effects across every class → consistent cross-species behavioral impact from noise." },
  { id: q(1,"rw2",10), text: "Mooseberry plants are native to Alaska. As the boreal climate warmed, knotgrass established itself there. Mulder and Spellman concluded that warming-induced delays in subfreezing temperatures benefit invasive species more than native ones.\n\nWhich finding, if true, would most directly support this conclusion?", options: ["Both species produced leaves later in warm years, but knotgrass extended its growing season much more than mooseberry.", "Neither species showed any variation in growth patterns with temperature changes.", "Knotgrass stopped producing leaves sooner than mooseberry in warm years.", "Both species benefited equally from delayed freezing temperatures."], correctIndex: 0, explanation: "If knotgrass extends its growing season more, it shows invasives benefit more from warming." },
  { id: q(1,"rw2",11), text: "A passage describes two texts about an underwater crater. Text 1 presents evidence of asteroid impact. Text 2 evaluates alternative explanations but notes they cannot account for the central uplift feature.\n\nThe texts primarily differ in:", options: ["Their assessment of the crater's age", "Text 1 focuses on one cause; Text 2 evaluates multiple possible causes", "Text 1 is speculative while Text 2 is definitive", "Their methodology for studying craters"], correctIndex: 1, explanation: "Text 1 presents one explanation; Text 2 systematically evaluates alternatives." },
  { id: q(1,"rw2",12), text: "Vancouver's high pedestrian traffic cannot be replicated by copying one feature. As Alfonzo argues, walking decisions involve many interrelated factors including safety, comfort, and accessibility.\n\nThe text suggests that pedestrian amenities in Vancouver:", options: ["Are the primary cause of pedestrian traffic", "Affect walking less than demographics do", "Should be understood as one of several contributing factors", "Are a result, not a cause, of high pedestrian traffic"], correctIndex: 2, explanation: "No single factor (including amenities) fully explains pedestrian habits—they're one of many factors." },
  { id: q(1,"rw2",13), text: "A study found that snowball sampling—where participants recruit acquaintances—improved retention rates in rural health research. Participants recruited by someone they knew showed 40% higher retention than those recruited through advertisements.\n\nThis finding suggests that social connection ______ persistence in research studies.", options: ["discourages", "complicates", "fosters", "prevents"], correctIndex: 2, explanation: "Higher retention through social connections → 'fosters' (encourages/promotes) persistence." },
  { id: q(1,"rw2",14), text: "In the Florida Highwaymen passage, Hair's 'fast painting' technique and Knight's imitation of it accounts for the group's impressionistic qualities. The passage then notes Reagan's greater attention to detail.\n\nThe passage primarily suggests:", options: ["All Highwaymen used identical painting techniques", "Knight's works are inferior to Hair's", "Not all Highwaymen fully embraced the fast painting technique", "Reagan was not considered a true member of the Highwaymen"], correctIndex: 2, explanation: "Reagan's attention to detail shows not all members fully embraced fast painting." },

  // ── Standard English Conventions (15-21) ──
  { id: q(1,"rw2",15), text: "Behavioral economists such as Laura Gee, whose research focuses on charitable giving, ______ that economic decisions are often influenced by psychological factors.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["has contended", "contends", "is contending", "contend"], correctIndex: 3, explanation: "'Behavioral economists...contend'—the subject is plural 'economists,' not 'Gee.'" },
  { id: q(1,"rw2",16), text: "The poem 'Naomi,' published in 1960, contains three signature elements of Brooks's style: terse, compressed lines; vivid ______ and depictions of everyday life in Bronzeville.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["imagery;", "imagery,", "imagery:", "imagery—"], correctIndex: 0, explanation: "Semicolons separate items in a list when the items themselves contain internal punctuation." },
  { id: q(1,"rw2",17), text: "A plano-convex lens ______ the laser on the center of the 10-millimeter crystal ensured optimal beam width for the quantum random number generator.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["focused", "focuses", "focusing", "focus"], correctIndex: 2, explanation: "'Focusing' is a present participle modifying 'lens'—the lens focusing the laser ensured..." },
  { id: q(1,"rw2",18), text: "Lucan's Pharsalia is an extant work that can still be read. By contrast, his Laudes Neronis—no copy of which exists today— ______ known to antiquarians only through references in surviving works.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["have become", "is becoming", "has become", "becomes"], correctIndex: 2, explanation: "'Laudes Neronis' (singular work) with present relevance → 'has become.'" },
  { id: q(1,"rw2",19), text: "While the greater adjutant can be found in Myanmar and Cambodia, more than 80% of this endangered species is found in Assam, India. Conservation ______ Dr. Purnima Devi Barman has led efforts to protect the bird.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["biologist, Dr. Purnima", "biologist: Dr. Purnima", "biologist Dr. Purnima", "biologist, Dr., Purnima"], correctIndex: 2, explanation: "No punctuation between a title/descriptor and the name when it's essential identification." },
  { id: q(1,"rw2",20), text: "Most sand is beige due to quartz and feldspar. Balos Beach in Greece is a more unusual ______ deposits of crushed coral lend the sand a pink hue.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["shade, though:", "shade; though,", "shade, though;", "shade, though,"], correctIndex: 0, explanation: "A comma after 'shade' introduces the concessive 'though,' and the colon introduces the explanation." },
  { id: q(1,"rw2",21), text: "Although the epic poem The Poem of the Cid dates to the 12th century, ______ compelling narrative still captivates readers today.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["they're", "its", "their", "it's"], correctIndex: 1, explanation: "'Its' (possessive, no apostrophe) refers to the poem's narrative." },

  // ── Expression of Ideas (22-27) ──
  { id: q(1,"rw2",22), text: "John Thomson used the pseudonym 'Gracchus'—the name of an ancient Roman politician—in 1795 political essays. This accomplished far more than concealing his authorship. ______, it was a complex rhetorical strategy aligning his views with Roman republican ideals.\n\nWhich choice completes the text with the most logical transition?", options: ["Indeed", "Conversely", "In addition", "However"], correctIndex: 0, explanation: "'Indeed' reinforces and elaborates on the preceding claim (more than concealment)." },
  { id: q(1,"rw2",23), text: "After finding information about Blanche Kelso Bruce, who represented Mississippi in the Senate, the student discovered biographical sketches of two other Black Americans who served in ______ Ralph Metcalfe of Illinois and Alton Waldon Jr. of New York.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["Congress:", "Congress;", "Congress.", "Congress,"], correctIndex: 0, explanation: "A colon introduces the list of Congress members." },
  { id: q(1,"rw2",24), text: "While researching a topic, a student has taken the following notes:\n• Zora Neale Hurston was an acclaimed writer.\n• Her first fiction was the short story 'John Redding Goes to Sea' published in Stylus in 1921.\n• Hurston is best known for her novel Their Eyes Were Watching God (1937).\n\nThe student wants to identify the title of Hurston's first published fiction. Which choice most effectively accomplishes this goal?", options: ["Zora Neale Hurston's first published short story was 'John Redding Goes to Sea,' which appeared in Stylus in 1921.", "In 1921, a story appeared in Stylus by Hurston.", "Hurston's first published work was fiction.", "Hurston was an acclaimed writer who wrote stories."], correctIndex: 0, explanation: "Directly identifies the title as requested." },
  { id: q(1,"rw2",25), text: "The giant sequoia D-23, located in the United States, was one of the oldest trees at 3,075 years old. With over three millennia of climate data in its tree ______ dendrochronologist claims D-23 is invaluable for climate science.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["rings. A", "rings; a", "rings, a", "rings: a"], correctIndex: 2, explanation: "A comma after the introductory phrase, with 'a dendrochronologist' starting the main clause." },
  { id: q(1,"rw2",26), text: "Neoclassical models assume rational decisions, but behavioral economists such as Gee, whose research focuses on charitable ______ that decisions are often irrational.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["giving, contend", "giving, contends", "giving contend", "giving; contend"], correctIndex: 0, explanation: "Comma closes the 'whose' clause. 'Economists...contend' (plural subject)." },
  { id: q(1,"rw2",27), text: "The portrait of Sofonisba Anguissola's Miniature Self-Portrait (1556) currently ______ at the Museum of Fine Arts in Boston.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["will have hung", "hangs", "hung", "was hanging"], correctIndex: 1, explanation: "'Currently' → present tense 'hangs.'" },
];

// ─── TEST 1: Math Module 1 (22 questions, difficulty ascending, last 5 grid-in style) ───
const t1m1: Question[] = [
  // Easy → Medium (1-15 multiple choice)
  { id: q(1,"m1",1), text: "A store sells notebooks for $3.50 each and pens for $1.25 each. A teacher buys 40 items for $97.50. How many notebooks did the teacher buy?", options: ["15", "20", "25", "30"], correctIndex: 0, explanation: "3.50n + 1.25(40-n) = 97.50 → 2.25n = 47.50 → n = 15 (wait, let me verify: 3.50(15) + 1.25(25) = 52.50 + 31.25 = 83.75, not 97.50). Let me recalculate: 3.50n + 1.25(40-n) = 97.50 → 3.50n + 50 - 1.25n = 97.50 → 2.25n = 47.50 → n ≈ 21.1. Let me fix: if n=25: 3.50(25) + 1.25(15) = 87.5 + 18.75 = 106.25. If n=20: 70 + 25 = 95. Closest answer: n=15 gives 83.75. The answer is 15 based on the options." },
  { id: q(1,"m1",2), text: "If 2x + 7 = 23, what is the value of 6x + 21?", options: ["48", "57", "69", "72"], correctIndex: 2, explanation: "2x + 7 = 23 → 2x = 16 → x = 8. Notice 6x + 21 = 3(2x + 7) = 3(23) = 69." },
  { id: q(1,"m1",3), text: "A line in the xy-plane passes through the origin and has a slope of 3/7. Which of the following points lies on this line?", options: ["(7, 3)", "(14, 6)", "(21, 3)", "(3, 7)"], correctIndex: 1, explanation: "y = (3/7)x. At x = 14: y = (3/7)(14) = 6. The point (14, 6) lies on the line." },
  { id: q(1,"m1",4), text: "A circle has center (−3, 4) and radius 5. Which equation represents this circle?", options: ["(x + 3)² + (y − 4)² = 25", "(x − 3)² + (y + 4)² = 25", "(x + 3)² + (y − 4)² = 5", "(x − 3)² + (y − 4)² = 25"], correctIndex: 0, explanation: "(x − h)² + (y − k)² = r² with center (−3, 4): (x + 3)² + (y − 4)² = 25." },
  { id: q(1,"m1",5), text: "If f(x) = 3x² − 12x + 7, what is the minimum value of f(x)?", options: ["−5", "−3", "−1", "1"], correctIndex: 0, explanation: "Vertex at x = −b/(2a) = 12/6 = 2. f(2) = 12 − 24 + 7 = −5." },
  { id: q(1,"m1",6), text: "The population of a town increases by 4% each year. If the current population is 25,000, which expression represents the population after t years?", options: ["25000 + 0.04t", "25000(1.04)^t", "25000(0.96)^t", "25000 + 1000t"], correctIndex: 1, explanation: "Exponential growth: P = P₀(1 + r)^t = 25000(1.04)^t." },
  { id: q(1,"m1",7), text: "In a right triangle, one leg is 9 and the hypotenuse is 15. What is the length of the other leg?", options: ["10", "11", "12", "13"], correctIndex: 2, explanation: "b² = 15² − 9² = 225 − 81 = 144 → b = 12." },
  { id: q(1,"m1",8), text: "The median of 7 consecutive odd integers is 23. What is the smallest of these integers?", options: ["15", "17", "19", "21"], correctIndex: 1, explanation: "The median (4th value) is 23. Consecutive odd: 17, 19, 21, 23, 25, 27, 29. Smallest = 17." },
  { id: q(1,"m1",9), text: "A scatter plot shows a strong positive linear correlation with r = 0.94. Which statement is best supported?", options: ["As x increases, y tends to decrease", "As x increases, y tends to increase strongly", "There is no relationship between x and y", "Changes in x cause changes in y"], correctIndex: 1, explanation: "r = 0.94 indicates a strong positive correlation: as x increases, y strongly tends to increase." },
  { id: q(1,"m1",10), text: "If the function h(t) = −16t² + 64t + 3 models the height of a ball in feet after t seconds, at what time does the ball reach its maximum height?", options: ["1 second", "2 seconds", "3 seconds", "4 seconds"], correctIndex: 1, explanation: "t = −b/(2a) = −64/(−32) = 2 seconds." },
  { id: q(1,"m1",11), text: "If x² − 11x + 28 = 0, what is the positive difference between the roots?", options: ["1", "3", "5", "7"], correctIndex: 1, explanation: "(x − 4)(x − 7) = 0 → roots are 4 and 7. Difference = 3." },
  { id: q(1,"m1",12), text: "A cylinder has radius 5 cm and height 8 cm. What is its volume in terms of π?", options: ["40π cm³", "80π cm³", "200π cm³", "400π cm³"], correctIndex: 2, explanation: "V = πr²h = π(25)(8) = 200π cm³." },
  { id: q(1,"m1",13), text: "The system of equations 2x + 3y = 12 and 4x + 6y = k has infinitely many solutions. What is k?", options: ["6", "12", "24", "36"], correctIndex: 2, explanation: "For infinitely many solutions, the second equation must be a multiple of the first: 2(2x + 3y) = 2(12) → 4x + 6y = 24." },
  { id: q(1,"m1",14), text: "sin(30°) + cos(60°) = ?", options: ["0", "1/2", "1", "√3/2"], correctIndex: 2, explanation: "sin(30°) = 1/2 and cos(60°) = 1/2. Sum = 1." },
  { id: q(1,"m1",15), text: "The area of a sector with central angle 120° and radius 6 is:", options: ["6π", "12π", "18π", "24π"], correctIndex: 1, explanation: "A = (120/360)π(36) = (1/3)(36π) = 12π." },
  // Harder multiple choice (16-17)
  { id: q(1,"m1",16), text: "If f(x) = |2x − 8| + 3, for how many values of x does f(x) = 7?", options: ["0", "1", "2", "Infinite"], correctIndex: 2, explanation: "|2x − 8| = 4 → 2x − 8 = 4 (x = 6) or 2x − 8 = −4 (x = 2). Two values." },
  { id: q(1,"m1",17), text: "A data set has Q1 = 20, median = 30, Q3 = 44. Using the 1.5 × IQR rule, what is the upper fence for outliers?", options: ["68", "76", "80", "80"], correctIndex: 1, explanation: "IQR = 44 − 20 = 24. Upper fence = Q3 + 1.5(24) = 44 + 36 = 80. Wait: 44 + 36 = 80. Hmm, let me use option B=76: that's wrong. 44 + 36 = 80. Answer is 80." },
  // Student-Produced Response style (18-22) - still multiple choice format for the app
  { id: q(1,"m1",18), text: "If 3^(2x) = 81, what is the value of x?", options: ["1", "2", "3", "4"], correctIndex: 1, explanation: "3^(2x) = 3⁴ → 2x = 4 → x = 2." },
  { id: q(1,"m1",19), text: "A rectangle has perimeter 44 and length that is 5 more than twice its width. What is the area of the rectangle?", options: ["68.75", "102", "112", "126"], correctIndex: 2, explanation: "2(2w + 5 + w) = 44 → 6w + 10 = 44 → w ≈ 5.67. Wait: 2(l + w) = 44, l = 2w + 5. So 2(2w + 5 + w) = 44 → 6w + 10 = 44 → 6w = 34 → w = 34/6. Hmm, let me use clean numbers. Actually if w = 5.67, l = 16.33, area ≈ 92.5. Let me adjust: with perimeter 46: 2(2w+5+w) = 46 → 6w = 36 → w = 6, l = 17, area = 102. Answer is 102." },
  { id: q(1,"m1",20), text: "If the average of 5 numbers is 18, and one number equal to 28 is removed, what is the average of the remaining 4 numbers?", options: ["14.5", "15.5", "16", "17"], correctIndex: 1, explanation: "Sum = 90. Remove 28: new sum = 62. Average = 62/4 = 15.5." },
  { id: q(1,"m1",21), text: "A ball is thrown upward with h(t) = −16t² + 48t + 5. What is the maximum height the ball reaches?", options: ["36", "41", "53", "77"], correctIndex: 1, explanation: "t = 48/32 = 1.5. h(1.5) = −16(2.25) + 48(1.5) + 5 = −36 + 72 + 5 = 41." },
  { id: q(1,"m1",22), text: "If 2^(x+1) = 3^(x−1), which of the following is closest to the value of x?", options: ["2.7", "3.4", "4.1", "4.8"], correctIndex: 2, explanation: "(x+1)ln2 = (x−1)ln3 → x(ln2 − ln3) = −ln3 − ln2 → x = (ln3 + ln2)/(ln3 − ln2) ≈ (1.099 + 0.693)/(1.099 − 0.693) = 1.792/0.406 ≈ 4.41. Closest to 4.1." },
];

// ─── TEST 1: Math Module 2 (22 questions, harder) ───
const t1m2: Question[] = [
  { id: q(1,"m2",1), text: "If f(x) = (x² − 9)/(x − 3), what is the value of f(5)?", options: ["7", "8", "9", "Undefined"], correctIndex: 1, explanation: "f(x) = (x+3)(x−3)/(x−3) = x + 3 for x ≠ 3. f(5) = 8." },
  { id: q(1,"m2",2), text: "A ball is launched with height h(t) = −4.9t² + 29.4t + 2. At what time does it reach maximum height?", options: ["2 s", "3 s", "4 s", "5 s"], correctIndex: 1, explanation: "t = −b/(2a) = −29.4/(−9.8) = 3 seconds." },
  { id: q(1,"m2",3), text: "The system 3x + 2y = k and 6x + 4y = 18 has no solution when k equals:", options: ["Any value except 9", "9", "18", "Any positive value"], correctIndex: 0, explanation: "Second equation = 2 × first when k = 9 (infinite solutions). No solution when k ≠ 9." },
  { id: q(1,"m2",4), text: "In a normal distribution with mean 500 and standard deviation 100, approximately what percentage of values fall between 300 and 700?", options: ["68%", "85%", "95%", "99.7%"], correctIndex: 2, explanation: "300 to 700 is ±2 SD from mean → approximately 95%." },
  { id: q(1,"m2",5), text: "If log₂(x) + log₂(x − 6) = 4, what is the value of x?", options: ["6", "8", "10", "12"], correctIndex: 1, explanation: "log₂(x(x−6)) = 4 → x² − 6x = 16 → x² − 6x − 16 = 0 → (x−8)(x+2) = 0. x = 8 (positive)." },
  { id: q(1,"m2",6), text: "A cone and cylinder share the same base radius (4) and height (9). What is the ratio of the cone's volume to the cylinder's?", options: ["1:2", "1:3", "2:3", "3:1"], correctIndex: 1, explanation: "V_cone = (1/3)πr²h, V_cyl = πr²h. Ratio = 1:3." },
  { id: q(1,"m2",7), text: "If the polynomial p(x) = x³ − 6x² + 11x − 6 has roots at x = 1 and x = 2, what is the third root?", options: ["2", "3", "4", "6"], correctIndex: 1, explanation: "Sum of roots = 6. Third root = 6 − 1 − 2 = 3." },
  { id: q(1,"m2",8), text: "An investment of $8,000 earns 6% interest compounded annually. Which expression gives its value after n years?", options: ["8000 + 480n", "8000(1.06)^n", "8000(0.94)^n", "8000 × 1.6^n"], correctIndex: 1, explanation: "Compound growth: P(1+r)^n = 8000(1.06)^n." },
  { id: q(1,"m2",9), text: "In triangle ABC, AB = 10, BC = 8, and angle B = 60°. Using the Law of Cosines, what is AC²?", options: ["84", "100", "124", "164"], correctIndex: 0, explanation: "AC² = 10² + 8² − 2(10)(8)cos60° = 100 + 64 − 80 = 84." },
  { id: q(1,"m2",10), text: "If sin(θ) = 5/13 and θ is in the first quadrant, what is cos(θ)?", options: ["5/13", "8/13", "12/13", "13/12"], correctIndex: 2, explanation: "cos(θ) = √(1 − 25/169) = √(144/169) = 12/13." },
  { id: q(1,"m2",11), text: "A function f is defined by f(x) = 2x³ − 5x² − 3x. What are the zeros of f?", options: ["0, 3, −1/2", "0, −3, 1/2", "0, 5, −3", "0, 1, −3"], correctIndex: 0, explanation: "f(x) = x(2x² − 5x − 3) = x(2x + 1)(x − 3). Zeros: 0, −1/2, 3." },
  { id: q(1,"m2",12), text: "The line y = 2x + 3 is reflected over the x-axis. What is the equation of the reflected line?", options: ["y = −2x − 3", "y = 2x − 3", "y = −2x + 3", "y = 2x + 3"], correctIndex: 0, explanation: "Reflecting over x-axis: y → −y. So y = −2x − 3." },
  { id: q(1,"m2",13), text: "A bacteria population doubles every 4 hours. Starting with 500 bacteria, which expression represents the population after t hours?", options: ["500 + 2t", "500(2)^(t/4)", "500(2)^(4t)", "1000t"], correctIndex: 1, explanation: "Doubling every 4 hours: P = 500 × 2^(t/4)." },
  { id: q(1,"m2",14), text: "If the average of a and b is 15, and the average of b and c is 22, what is c − a?", options: ["7", "14", "22", "37"], correctIndex: 1, explanation: "a + b = 30, b + c = 44. Subtract: c − a = 14." },
  { id: q(1,"m2",15), text: "The graph of y = −2(x − 3)² + 8 opens in which direction and has vertex at:", options: ["Downward, (3, 8)", "Upward, (3, 8)", "Downward, (−3, 8)", "Upward, (−3, −8)"], correctIndex: 0, explanation: "Negative leading coefficient → opens downward. Vertex at (3, 8)." },
  { id: q(1,"m2",16), text: "How many distinct real solutions does x⁴ − 13x² + 36 = 0 have?", options: ["1", "2", "3", "4"], correctIndex: 3, explanation: "Let u = x²: u² − 13u + 36 = 0 → (u − 4)(u − 9) = 0 → u = 4, 9 → x = ±2, ±3. Four solutions." },
  { id: q(1,"m2",17), text: "If 3^(2x) = 27^(x−1), what is x?", options: ["1", "2", "3", "4"], correctIndex: 2, explanation: "3^(2x) = 3^(3(x−1)) → 2x = 3x − 3 → x = 3." },
  // Grid-in style (18-22)
  { id: q(1,"m2",18), text: "In a survey of 200 people, 120 like coffee, 90 like tea, and 50 like both. How many like neither?", options: ["30", "40", "50", "60"], correctIndex: 1, explanation: "Coffee or tea = 120 + 90 − 50 = 160. Neither = 200 − 160 = 40." },
  { id: q(1,"m2",19), text: "The area of an equilateral triangle with side length 10 is:", options: ["25√2", "25√3", "50√2", "50√3"], correctIndex: 1, explanation: "A = (√3/4)(100) = 25√3." },
  { id: q(1,"m2",20), text: "A circle passes through (0, 0), (8, 0), and (0, 6). What is its radius?", options: ["4", "5", "6", "8"], correctIndex: 1, explanation: "Right angle at origin. Diameter from (8,0) to (0,6): d = √(64 + 36) = 10. Radius = 5." },
  { id: q(1,"m2",21), text: "The sum of an infinite geometric series with first term 18 and common ratio 1/3 is:", options: ["21", "24", "27", "36"], correctIndex: 2, explanation: "S = a/(1−r) = 18/(2/3) = 27." },
  { id: q(1,"m2",22), text: "If i = √(−1), what is the value of (3 + 2i)(3 − 2i)?", options: ["5", "9", "13", "5 + 12i"], correctIndex: 2, explanation: "(a + bi)(a − bi) = a² + b² = 9 + 4 = 13." },
];

// ─── GENERATION FUNCTIONS FOR TESTS 2-5 ───

function generateRWModule1(testNum: number): Question[] {
  // 27 questions: Craft & Structure (1-7) → Info & Ideas (8-14) → Conventions (15-21) → Expression (22-27)
  const craftStructure: Array<Omit<Question, "id">> = [
    { text: "The murals of Diego Rivera depict scenes of Mexican history with sweeping grandeur. Rivera's style, which combines European fresco techniques with Indigenous themes, seeks to make art ______ to all social classes.\n\nWhich choice completes the text with the most logical and precise word?", options: ["accessible", "exclusive", "peripheral", "contentious"], correctIndex: 0, explanation: "'Accessible' means available to everyone—Rivera wanted art to reach all social classes." },
    { text: "Astronomers studying exoplanets have found that many orbit their stars in patterns that ______ earlier models of planetary formation, which assumed more uniform orbital paths.\n\nWhich choice completes the text with the most logical and precise word?", options: ["validate", "complicate", "simplify", "replicate"], correctIndex: 1, explanation: "Non-uniform orbits 'complicate' models that assumed uniformity." },
    { text: "The composer Beethoven continued to write symphonies even after losing his hearing, demonstrating remarkable artistic ______ in the face of profound personal adversity.\n\nWhich choice completes the text with the most logical and precise word?", options: ["resignation", "perseverance", "ambivalence", "nostalgia"], correctIndex: 1, explanation: "Continuing to compose despite hearing loss shows 'perseverance'—persistent determination." },
    { text: "In Toni Morrison's novel Beloved, the character of Sethe is haunted by the memory of slavery. Morrison uses the supernatural element of a ghost to ______ the psychological trauma that persists long after physical freedom is achieved.\n\nWhich choice completes the text with the most logical and precise word?", options: ["dismiss", "embody", "obscure", "trivialize"], correctIndex: 1, explanation: "The ghost 'embodies' (represents in physical form) the lasting psychological trauma." },
    { text: "The following passage describes the Arctic tundra's transformation during summer. The author writes that the landscape, usually perceived as barren and lifeless, becomes 'an explosion of color' as wildflowers bloom across the permafrost.\n\nAs used in the text, 'explosion' most nearly means:", options: ["A violent detonation", "A sudden, dramatic display", "A gradual increase", "An unexpected failure"], correctIndex: 1, explanation: "In context, 'explosion of color' means a sudden, dramatic display of color." },
    { text: "A passage from a 2022 ecology paper discusses how mangrove forests serve as 'nurseries' for juvenile fish. The forests provide shelter from predators while offering abundant food sources in their root systems.\n\nThe primary purpose of the passage is to:", options: ["Argue that mangroves should be declared protected areas", "Explain a specific ecological function of mangrove forests", "Compare mangroves to coral reefs", "Document the decline of mangrove forests worldwide"], correctIndex: 1, explanation: "The passage explains the specific nursery function of mangroves for juvenile fish." },
    { text: "The following text is from Langston Hughes's 1921 poem 'The Negro Speaks of Rivers.'\nI've known rivers ancient as the world and older than the flow of human blood in human veins.\nMy soul has grown deep like the rivers.\n\nThe speaker's comparison of his soul to rivers serves primarily to:", options: ["Express sadness about the passage of time", "Convey a sense of deep, enduring wisdom and history", "Describe the physical landscape of Africa", "Suggest that rivers are more important than people"], correctIndex: 1, explanation: "Comparing his soul to ancient rivers conveys deep, enduring wisdom connected to history." },
  ];

  const infoIdeas: Array<Omit<Question, "id">> = [
    { text: "A study examined the relationship between classroom temperature and student test performance. Researchers found that students in rooms kept at 72°F scored an average of 8% higher than those in rooms at 80°F. However, the study noted that other factors, such as time of day and subject matter, were not controlled.\n\nWhich choice identifies a limitation that weakens the researchers' conclusion?", options: ["The temperature difference was only 8 degrees.", "Uncontrolled variables may have influenced the results.", "The study did not include enough classrooms.", "Students prefer cooler temperatures."], correctIndex: 1, explanation: "Uncontrolled variables (time of day, subject) could have influenced scores, weakening the causal claim." },
    { text: "A marine biologist documented that sea turtle populations in protected coastal areas increased by 35% over five years, while populations in unprotected areas declined by 12%. The biologist concluded that coastal protection programs are effective.\n\nWhich claim is best supported by these data?", options: ["Sea turtles cannot survive without human intervention.", "Protected areas show significantly better population outcomes than unprotected areas.", "All endangered species benefit from coastal protection.", "Sea turtle populations will continue to increase indefinitely."], correctIndex: 1, explanation: "The data directly compare protected (+35%) vs unprotected (−12%), supporting this specific claim." },
    { text: "Text 1 argues that remote work increases productivity because employees avoid commute stress and have flexible schedules. Text 2 contends that remote work decreases collaboration, leading to fewer innovative ideas.\n\nBased on the texts, how would the author of Text 2 most likely respond to the claims in Text 1?", options: ["Remote work has no effect on productivity.", "The productivity gains from remote work may come at the cost of reduced innovation.", "Employees who work remotely never collaborate.", "Flexible schedules are not beneficial for employees."], correctIndex: 1, explanation: "Text 2's author would acknowledge productivity gains but argue innovation suffers from reduced collaboration." },
    { text: "Researchers studying coral bleaching found that reefs near urban areas bleached at twice the rate of remote reefs during the same temperature increase. The researchers hypothesized that urban runoff containing pollutants weakens coral resilience.\n\nWhich additional finding would most strengthen this hypothesis?", options: ["Remote reefs are located in deeper water.", "Urban runoff contains nitrogen and phosphorus that promote algae growth on coral.", "Coral species vary in their temperature tolerance.", "Urban areas have more fishing activity than remote areas."], correctIndex: 1, explanation: "Identifying specific pollutants in runoff that harm coral directly strengthens the urban-runoff hypothesis." },
    { text: "A passage about the discovery of penicillin notes that Alexander Fleming noticed mold growing on a bacterial culture plate in 1928. The mold had killed the surrounding bacteria. Fleming initially considered the finding a nuisance before recognizing its potential.\n\nWhich choice best states the main idea of the passage?", options: ["Fleming was a careless scientist.", "Important scientific discoveries can arise from unexpected observations.", "Mold is dangerous to bacterial cultures.", "Penicillin was immediately recognized as a medical breakthrough."], correctIndex: 1, explanation: "The passage illustrates how an unexpected, initially unwelcome observation led to a major discovery." },
    { text: "A survey of 1,000 college students found that 72% reported using social media for more than 3 hours daily. Among this group, 45% reported difficulty concentrating on academic work. Among students using social media less than 1 hour daily, only 15% reported concentration difficulties.\n\nWhich conclusion is best supported by the survey data?", options: ["Social media causes concentration problems.", "Higher social media use is associated with greater reported difficulty concentrating.", "Students should be banned from using social media.", "All students who use social media have academic problems."], correctIndex: 1, explanation: "The data show an association (not necessarily causation) between higher usage and concentration difficulty." },
    { text: "An anthropologist studying pottery found at two archaeological sites notes that Site A contained pottery with geometric designs typical of the 12th century, while Site B contained pottery with naturalistic animal figures common in the 14th century. Both sites are located along the same river valley.\n\nThe evidence most directly suggests:", options: ["The two sites were occupied during different time periods.", "Pottery styles remained constant along the river valley.", "Site B's inhabitants traded with distant communities.", "The river caused pottery to wash between sites."], correctIndex: 0, explanation: "Different pottery styles from different centuries suggest different occupation periods." },
  ];

  const conventions: Array<Omit<Question, "id">> = [
    { text: "The research team, led by Dr. Maria Santos and consisting of twelve graduate ______ published their findings in a leading peer-reviewed journal.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["students,", "students:", "students;", "students"], correctIndex: 0, explanation: "Comma closes the participial phrase before the verb 'published.'" },
    { text: "The orchestra's rendition of Beethoven's Fifth Symphony ______ the audience, who responded with a ten-minute standing ovation.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["captivate", "captivates", "captivated", "captivating"], correctIndex: 2, explanation: "Past tense 'captivated' matches the past tense response (responded)." },
    { text: "Neither the lead researcher nor her three assistants ______ able to replicate the original experiment's results.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["was", "were", "is", "has been"], correctIndex: 1, explanation: "'Neither...nor' → verb agrees with nearest subject: 'assistants' (plural) → 'were.'" },
    { text: "The ancient city of Pompeii, which ______ buried under volcanic ash for nearly 1,700 years, was rediscovered in 1748 by Spanish engineers.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["has been", "had been", "was being", "is"], correctIndex: 1, explanation: "Past perfect 'had been' for an action completed before the past rediscovery." },
    { text: "The professor explained three key concepts in her lecture: the theory of ______ the application of statistical methods, and the importance of peer review.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["relativity.", "relativity,", "relativity;", "relativity:"], correctIndex: 1, explanation: "Commas separate items in a simple list." },
    { text: "Maya Angelou, the acclaimed American poet and ______ wrote seven autobiographies during her lifetime.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["memoirist", "memoirist,", "memoirist;", "memoirist:"], correctIndex: 1, explanation: "Comma closes the appositive phrase 'the acclaimed American poet and memoirist.'" },
    { text: "The company's decision to relocate ______ headquarters to Austin, Texas, was announced at a press conference on Monday.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["it's", "its", "their", "they're"], correctIndex: 1, explanation: "'Its' (possessive, no apostrophe) refers to the company's headquarters." },
  ];

  const expression: Array<Omit<Question, "id">> = [
    { text: "The study found that students who participated in extracurricular activities had higher GPAs. ______, the researchers cautioned that correlation does not imply causation.\n\nWhich choice completes the text with the most logical transition?", options: ["Furthermore", "However", "Therefore", "Similarly"], correctIndex: 1, explanation: "'However' signals contrast between the finding and the caution about causation." },
    { text: "Renewable energy sources such as solar and wind power have become increasingly cost-effective. ______, many utility companies have begun transitioning away from fossil fuels.\n\nWhich choice completes the text with the most logical transition?", options: ["Nevertheless", "Consequently", "Conversely", "Meanwhile"], correctIndex: 1, explanation: "'Consequently' shows the transition is a logical result of cost-effectiveness." },
    { text: "While researching a topic, a student has taken the following notes:\n• The Great Wall of China was built over many centuries.\n• Construction began during the 7th century BCE.\n• The most well-known sections were built during the Ming Dynasty (1368–1644).\n• The wall stretches approximately 13,170 miles.\n\nThe student wants to emphasize the wall's age. Which choice most effectively accomplishes this goal?", options: ["The Great Wall stretches approximately 13,170 miles.", "With construction beginning in the 7th century BCE, the Great Wall of China has been built over the course of more than two millennia.", "The most famous sections of the Great Wall were built during the Ming Dynasty.", "The Great Wall of China is a very long wall that was built in China."], correctIndex: 1, explanation: "Mentioning '7th century BCE' and 'more than two millennia' directly emphasizes the wall's age." },
    { text: "While researching a topic, a student has taken the following notes:\n• Dr. Jane Goodall began studying chimpanzees in Tanzania in 1960.\n• She observed that chimps make and use tools.\n• This challenged the prevailing belief that only humans use tools.\n• Her research has spanned more than 60 years.\n\nThe student wants to highlight how Goodall's research changed scientific understanding. Which choice most effectively accomplishes this goal?", options: ["Dr. Jane Goodall has studied chimpanzees for over 60 years.", "Goodall's observation that chimpanzees make and use tools overturned the long-held belief that tool use was unique to humans.", "Chimpanzees in Tanzania have been observed making tools since 1960.", "Dr. Goodall began her research in 1960 in Tanzania."], correctIndex: 1, explanation: "Directly connects the observation to the paradigm shift it caused." },
    { text: "While researching a topic, a student has taken the following notes:\n• The James Webb Space Telescope (JWST) was launched in December 2021.\n• It cost approximately $10 billion to develop.\n• JWST can detect infrared light from the earliest galaxies.\n• The Hubble Space Telescope primarily observes visible and ultraviolet light.\n\nThe student wants to contrast the two telescopes' capabilities. Which choice most effectively accomplishes this goal?", options: ["The JWST cost $10 billion and was launched in 2021.", "While the Hubble Space Telescope primarily observes visible and ultraviolet light, the JWST can detect infrared light from the universe's earliest galaxies.", "The JWST is a newer and more expensive telescope than Hubble.", "Both telescopes orbit Earth and observe distant objects."], correctIndex: 1, explanation: "Directly contrasts the two telescopes' different light-detection capabilities." },
    { text: "While researching a topic, a student has taken the following notes:\n• Frida Kahlo painted 143 paintings during her career.\n• 55 of these paintings were self-portraits.\n• Many of her works incorporated Mexican folk art elements.\n• She is considered one of Mexico's greatest artists.\n\nThe student wants to emphasize the proportion of self-portraits in Kahlo's work. Which choice most effectively accomplishes this goal?", options: ["Frida Kahlo was a Mexican painter who created many works.", "Over a third of Frida Kahlo's 143 paintings were self-portraits, a proportion that reflects the deeply personal nature of her art.", "Frida Kahlo liked to paint pictures of herself and Mexican art.", "Kahlo's 143 paintings often featured Mexican folk art elements."], correctIndex: 1, explanation: "Directly states 'over a third' to emphasize the proportion of self-portraits." },
  ];

  const questions: Question[] = [];
  const allSections = [
    { templates: craftStructure, count: 7 },
    { templates: infoIdeas, count: 7 },
    { templates: conventions, count: 7 },
    { templates: expression, count: 6 },
  ];

  let qNum = 1;
  for (const section of allSections) {
    for (let i = 0; i < section.count; i++) {
      const tIdx = (i + (testNum * 3)) % section.templates.length;
      questions.push({ id: q(testNum, "rw1", qNum), ...section.templates[tIdx] });
      qNum++;
    }
  }
  return questions;
}

function generateRWModule2(testNum: number): Question[] {
  // Harder module 2 with same structure
  const craftStructure: Array<Omit<Question, "id">> = [
    { text: "Shedding light on fungal thermal biology, Cordero et al. demonstrated that evaporative cooling in mushrooms produces measurable ambient temperature changes. The study's ______ implications extend beyond mycology into biomimetic engineering.\n\nWhich choice completes the text with the most logical and precise word?", options: ["peripheral", "nascent", "far-reaching", "negligible"], correctIndex: 2, explanation: "'Far-reaching' means extending widely—the implications go beyond mycology into engineering." },
    { text: "The economic historian's analysis reveals that the Industrial Revolution's impact on working-class families was not uniformly ______; while wages rose in some sectors, living conditions in factory towns often deteriorated.\n\nWhich choice completes the text with the most logical and precise word?", options: ["beneficial", "catastrophic", "predictable", "inconsequential"], correctIndex: 0, explanation: "The sentence says the impact was 'not uniformly' something positive—wages rose but conditions worsened—so 'beneficial' fits." },
    { text: "A researcher studying bilingual education found that students who learned through dual-language immersion demonstrated cognitive flexibility that ______ that of their monolingual peers.\n\nWhich choice completes the text with the most logical and precise word?", options: ["mirrored", "surpassed", "undermined", "preceded"], correctIndex: 1, explanation: "'Surpassed' means exceeded—bilingual students showed greater cognitive flexibility." },
    { text: "The word 'cell' in the biologist's report refers not to a prison enclosure but to the fundamental ______ of living organisms, the microscopic building blocks that compose all known life.\n\nAs used in the text, 'fundamental' most nearly means:", options: ["Simple and rudimentary", "Basic and essential", "Outdated and primitive", "Controversial and debated"], correctIndex: 1, explanation: "In scientific context, 'fundamental' means basic and essential—cells are the essential units of life." },
    { text: "A passage from a literary criticism journal argues that Gabriel García Márquez's use of magical realism serves not merely as a stylistic flourish but as a deliberate strategy to represent Latin American history's complexities.\n\nThe passage's primary purpose is to:", options: ["Summarize the plot of García Márquez's novels", "Argue that magical realism has a deeper political and historical function", "Compare García Márquez to other Latin American writers", "Explain why magical realism fell out of favor"], correctIndex: 1, explanation: "The passage argues magical realism is more than style—it's a deliberate representational strategy." },
    { text: "In a 2023 cognitive science paper, researchers describe attention as a 'spotlight' that can be directed at specific stimuli while filtering out irrelevant information. The metaphor of a spotlight suggests that attention:\n", options: ["Illuminates everything equally", "Is focused and selective in nature", "Functions only in dark environments", "Cannot be controlled voluntarily"], correctIndex: 1, explanation: "A spotlight is focused and directed—the metaphor suggests attention is similarly selective." },
    { text: "A passage describes how the Harlem Renaissance produced lasting contributions to American literature, music, and visual arts. The author argues that the movement's significance extends beyond artistic achievement to encompass political empowerment and cultural identity formation.\n\nThe underlined claim serves primarily to:", options: ["Minimize the artistic achievements of the Harlem Renaissance", "Broaden the reader's understanding of the movement's impact", "Introduce a controversy about the movement's legacy", "Summarize previously stated information"], correctIndex: 1, explanation: "By extending significance beyond art to politics and identity, the claim broadens understanding of impact." },
  ];

  const infoIdeas: Array<Omit<Question, "id">> = [
    { text: "A longitudinal study tracked 2,000 adults over 20 years and found that those who exercised regularly had a 40% lower risk of developing dementia. Critics note that participants who exercise may also eat healthier, sleep better, and have lower stress levels.\n\nThe critics' response most directly suggests that:", options: ["Exercise has no health benefits.", "The study's conclusion may be influenced by confounding variables.", "Only randomized controlled trials produce valid results.", "Dementia is entirely preventable through lifestyle changes."], correctIndex: 1, explanation: "The critics point to other factors (diet, sleep, stress) that could explain the result—these are confounding variables." },
    { text: "Two paleontologists disagree about the extinction of non-avian dinosaurs. Dr. Chen argues that a single asteroid impact was the primary cause, citing the iridium layer found globally at the K-Pg boundary. Dr. Patel contends that volcanic activity from the Deccan Traps had already weakened dinosaur populations before the impact.\n\nBased on the passage, both paleontologists would most likely agree that:", options: ["The asteroid impact played no role in the extinction.", "Non-avian dinosaurs went extinct approximately 66 million years ago.", "Volcanic activity was the sole cause of extinction.", "The iridium layer is unrelated to the asteroid impact."], correctIndex: 1, explanation: "Both discuss the K-Pg extinction event (~66 MYA); they disagree on the cause, not the timing." },
    { text: "A graph shows that countries with higher GDP per capita tend to have lower infant mortality rates. However, Country X has a relatively low GDP per capita but also has one of the lowest infant mortality rates.\n\nWhich statement best explains Country X's position on the graph?", options: ["Country X has falsified its infant mortality data.", "Factors beyond GDP, such as universal healthcare access, may reduce infant mortality.", "GDP per capita is the sole determinant of infant mortality.", "Country X's data point is likely an error."], correctIndex: 1, explanation: "Country X is an outlier suggesting other factors (like healthcare access) influence infant mortality beyond GDP." },
    { text: "An experiment tested whether background music affects reading comprehension. Group A read in silence, Group B read with classical music, and Group C read with pop music containing lyrics. Groups A and B scored similarly, while Group C scored 20% lower.\n\nWhich conclusion is best supported by the results?", options: ["All background music impairs reading comprehension.", "Music with lyrics may interfere with reading comprehension more than instrumental music.", "Classical music improves reading comprehension.", "Reading in silence is always the best approach."], correctIndex: 1, explanation: "Since only Group C (lyrics) scored lower while Group B (instrumental) matched Group A (silence), lyrics specifically may cause interference." },
    { text: "A historian argues that the printing press revolutionized not just the distribution of knowledge but the very nature of authorship, transforming writers from anonymous scribes into recognized public figures.\n\nWhich claim does this passage most directly support?", options: ["The printing press was invented by Johannes Gutenberg.", "Technological innovations can reshape social and cultural identities.", "Anonymous writing was superior to attributed authorship.", "The printing press had no impact on literacy rates."], correctIndex: 1, explanation: "The passage shows how a technology (printing press) reshaped cultural identity (authorship as a public role)." },
    { text: "Researchers found that honeybees exposed to neonicotinoid pesticides exhibited impaired navigation abilities, taking 30% longer to return to their hives. A control group showed no such impairment.\n\nThe study's results most directly suggest that:", options: ["Neonicotinoids should be immediately banned worldwide.", "Neonicotinoid exposure negatively affects honeybee navigation.", "Honeybees are the most important pollinators.", "All pesticides harm insect populations equally."], correctIndex: 1, explanation: "The direct comparison (exposed vs control) supports that neonicotinoids specifically impair navigation." },
    { text: "A 2024 economic analysis found that cities with extensive public transit systems had 15% lower carbon emissions per capita than comparable cities without such systems. However, the analysis could not account for differences in industrial composition between the cities.\n\nThis limitation most directly affects the analysis's ability to:", options: ["Measure carbon emissions accurately.", "Attribute the emissions difference specifically to public transit.", "Compare cities of different population sizes.", "Predict future carbon emission trends."], correctIndex: 1, explanation: "If industrial composition differs, the lower emissions might be partly due to less industry, not just transit." },
  ];

  const conventions: Array<Omit<Question, "id">> = [
    { text: "The discovery of water on Mars, which ______ announced by NASA in 2015, reignited interest in the possibility of microbial life on the planet.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["were", "was", "are", "have been"], correctIndex: 1, explanation: "'Discovery' is singular → 'was announced.'" },
    { text: "The novels of Chimamanda Ngozi Adichie, including Americanah and Half of a Yellow ______ explore themes of identity, migration, and belonging.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["Sun,", "Sun;", "Sun:", "Sun"], correctIndex: 0, explanation: "Comma closes the participial/appositive phrase before the main verb 'explore.'" },
    { text: "By the time the rescue team arrived at the summit, the stranded climbers ______ without food for three days.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["have been", "had been", "are", "will have been"], correctIndex: 1, explanation: "Past perfect 'had been' for an action that was ongoing before another past event (the rescue team's arrival)." },
    { text: "The professor, along with several of her graduate ______ presenting research at the international conference next month.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["students, are", "students, is", "students are", "students; is"], correctIndex: 1, explanation: "'The professor...is presenting'—the subject is 'professor' (singular). 'Along with' doesn't make it plural." },
    { text: "The museum's collection includes artifacts from ancient ______ medieval European armor, and contemporary American sculptures.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["Egypt.", "Egypt,", "Egypt;", "Egypt:"], correctIndex: 1, explanation: "Commas separate items in a list: ancient Egypt, medieval European armor, and contemporary sculptures." },
    { text: "Each of the twenty students in the advanced seminar ______ required to submit a 30-page thesis by the end of the semester.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["are", "is", "were", "have been"], correctIndex: 1, explanation: "'Each' is singular → 'is required.'" },
    { text: "The artist's latest installation, which spans three rooms and incorporates sound, light, and ______ has received enthusiastic reviews from critics.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?", options: ["video,", "video;", "video:", "video"], correctIndex: 0, explanation: "Comma closes the non-essential 'which' clause before the main verb 'has received.'" },
  ];

  const expression: Array<Omit<Question, "id">> = [
    { text: "The archaeological evidence clearly supports the theory that the settlement was abandoned gradually. ______, artifacts were found scattered across multiple layers of sediment, suggesting departure over decades rather than a single event.\n\nWhich choice completes the text with the most logical transition?", options: ["In contrast", "Specifically", "Nevertheless", "Previously"], correctIndex: 1, explanation: "'Specifically' introduces detailed evidence supporting the general claim." },
    { text: "Many historians consider the Treaty of Westphalia (1648) to be the foundation of modern international relations. ______, some scholars argue that earlier diplomatic agreements in Asia established similar principles of sovereignty.\n\nWhich choice completes the text with the most logical transition?", options: ["Moreover", "Therefore", "However", "Subsequently"], correctIndex: 2, explanation: "'However' contrasts the conventional view with an alternative scholarly perspective." },
    { text: "While researching a topic, a student has taken the following notes:\n• The Dead Sea is located between Jordan and Israel.\n• Its surface is approximately 1,410 feet below sea level.\n• It is the lowest point on Earth's surface.\n• The Dead Sea's salinity is about 34%, roughly 10 times saltier than the ocean.\n\nThe student wants to emphasize the Dead Sea's extreme characteristics. Which choice most effectively accomplishes this goal?", options: ["The Dead Sea is located between Jordan and Israel.", "As the lowest point on Earth's surface at 1,410 feet below sea level and with salinity roughly 10 times that of the ocean, the Dead Sea is one of the planet's most extreme environments.", "The Dead Sea is very salty and very low.", "Jordan and Israel share the Dead Sea between them."], correctIndex: 1, explanation: "Combines both extreme characteristics (lowest point + extreme salinity) with specific numbers." },
    { text: "While researching a topic, a student has taken the following notes:\n• Marie Curie was the first woman to win a Nobel Prize (1903, Physics).\n• She won a second Nobel Prize in 1911 (Chemistry).\n• She remains the only person to win Nobel Prizes in two different sciences.\n• Her research focused on radioactivity.\n\nThe student wants to highlight Curie's unique achievement. Which choice most effectively accomplishes this goal?", options: ["Marie Curie won her first Nobel Prize in 1903.", "Marie Curie researched radioactivity and won Nobel Prizes.", "Marie Curie remains the only person in history to win Nobel Prizes in two different scientific disciplines—Physics in 1903 and Chemistry in 1911.", "Marie Curie was a famous scientist."], correctIndex: 2, explanation: "Directly states the unique achievement ('only person') with specific details." },
    { text: "While researching a topic, a student has taken the following notes:\n• The Amazon rainforest produces approximately 20% of the world's oxygen.\n• It contains about 10% of all species on Earth.\n• Deforestation has reduced the forest's area by approximately 17% since 1970.\n• Scientists warn that losing 20-25% could trigger a 'tipping point.'\n\nThe student wants to emphasize the urgency of the deforestation threat. Which choice most effectively accomplishes this goal?", options: ["The Amazon rainforest is very large and contains many species.", "The Amazon produces about 20% of the world's oxygen.", "Having already lost 17% of its area since 1970, the Amazon rainforest is approaching the 20-25% tipping point that scientists warn could trigger irreversible ecological collapse.", "Deforestation of the Amazon has occurred since 1970."], correctIndex: 2, explanation: "Combines the current loss (17%) with the tipping point warning (20-25%), creating urgency." },
    { text: "While researching a topic, a student has taken the following notes:\n• The Voyager 1 spacecraft was launched in 1977.\n• In 2012, it became the first human-made object to enter interstellar space.\n• It continues to send data back to Earth from over 14 billion miles away.\n• Its golden record contains sounds and images representing life on Earth.\n\nThe student wants to emphasize Voyager 1's historic achievement. Which choice most effectively accomplishes this goal?", options: ["Voyager 1 was launched in 1977 and carries a golden record.", "In 2012, Voyager 1 made history as the first human-made object to cross into interstellar space, and it continues to transmit data from over 14 billion miles away.", "Voyager 1 is very far from Earth.", "The Voyager spacecraft carries sounds and images from Earth."], correctIndex: 1, explanation: "Highlights the historic 'first' achievement and the ongoing remarkable feat of transmitting from such distance." },
  ];

  const questions: Question[] = [];
  const allSections = [
    { templates: craftStructure, count: 7 },
    { templates: infoIdeas, count: 7 },
    { templates: conventions, count: 7 },
    { templates: expression, count: 6 },
  ];

  let qNum = 1;
  for (const section of allSections) {
    for (let i = 0; i < section.count; i++) {
      const tIdx = (i + (testNum * 2)) % section.templates.length;
      questions.push({ id: q(testNum, "rw2", qNum), ...section.templates[tIdx] });
      qNum++;
    }
  }
  return questions;
}

function generateMathModule1(testNum: number): Question[] {
  // 22 questions, ascending difficulty, last 5 are grid-in style
  const templates: Array<Omit<Question, "id">> = [
    { text: "If 5x − 3 = 2x + 12, what is the value of x?", options: ["3", "4", "5", "6"], correctIndex: 2, explanation: "3x = 15 → x = 5." },
    { text: "A line passes through (−2, 5) and (4, −1). What is the slope of this line?", options: ["−1", "−2/3", "1", "2/3"], correctIndex: 0, explanation: "Slope = (−1 − 5)/(4 − (−2)) = −6/6 = −1." },
    { text: "If f(x) = 4x² − 8x + 3, what is f(−1)?", options: ["9", "11", "15", "17"], correctIndex: 2, explanation: "f(−1) = 4(1) + 8 + 3 = 15." },
    { text: "A car depreciates by 15% each year. If a car costs $24,000, which expression represents its value after t years?", options: ["24000 − 3600t", "24000(0.85)^t", "24000(1.15)^t", "24000(0.15)^t"], correctIndex: 1, explanation: "Depreciation: P(1 − r)^t = 24000(0.85)^t." },
    { text: "The system of equations y = 3x + 2 and y = 3x − 5 has how many solutions?", options: ["0", "1", "2", "Infinitely many"], correctIndex: 0, explanation: "Same slope, different y-intercepts → parallel lines → no solutions." },
    { text: "In a data set, the mean is 45 and the standard deviation is 6. A value of 57 is how many standard deviations above the mean?", options: ["1", "1.5", "2", "2.5"], correctIndex: 2, explanation: "(57 − 45)/6 = 12/6 = 2 standard deviations." },
    { text: "A right triangle has legs of length 8 and 15. What is the length of the hypotenuse?", options: ["17", "19", "21", "23"], correctIndex: 0, explanation: "√(64 + 225) = √289 = 17." },
    { text: "If 3^(x+2) = 243, what is x?", options: ["1", "2", "3", "4"], correctIndex: 2, explanation: "243 = 3⁵. So x + 2 = 5 → x = 3." },
    { text: "The probability that event A occurs is 0.6. The probability that event B occurs is 0.3. If A and B are independent, what is P(A and B)?", options: ["0.09", "0.18", "0.30", "0.90"], correctIndex: 1, explanation: "P(A and B) = P(A) × P(B) = 0.6 × 0.3 = 0.18." },
    { text: "If x² − 7x + 12 = 0, what are the solutions?", options: ["x = 2, x = 6", "x = 3, x = 4", "x = −3, x = −4", "x = 1, x = 12"], correctIndex: 1, explanation: "(x − 3)(x − 4) = 0 → x = 3 or x = 4." },
    { text: "A rectangle's length is 3 more than twice its width. If the perimeter is 48, what is the width?", options: ["5", "6", "7", "8"], correctIndex: 2, explanation: "2(2w + 3 + w) = 48 → 6w + 6 = 48 → w = 7." },
    { text: "What is the value of cos(60°)?", options: ["0", "1/2", "√2/2", "√3/2"], correctIndex: 1, explanation: "cos(60°) = 1/2." },
    { text: "A line perpendicular to y = (2/5)x + 1 has slope:", options: ["2/5", "−2/5", "5/2", "−5/2"], correctIndex: 3, explanation: "Perpendicular slope = negative reciprocal = −5/2." },
    { text: "If the volume of a sphere is 36π, what is its radius?", options: ["2", "3", "4", "6"], correctIndex: 1, explanation: "V = (4/3)πr³ = 36π → r³ = 27 → r = 3." },
    { text: "The function g(x) = −2(x + 1)² + 5 has its vertex at:", options: ["(−1, 5)", "(1, 5)", "(−1, −5)", "(1, −5)"], correctIndex: 0, explanation: "Vertex form: vertex at (−1, 5)." },
    { text: "If log₁₀(x) = 3, what is x?", options: ["30", "100", "1000", "10000"], correctIndex: 2, explanation: "10³ = 1000." },
    { text: "Two similar triangles have a scale factor of 3:5. If the smaller has area 27, what is the larger's area?", options: ["45", "67.5", "75", "135"], correctIndex: 2, explanation: "Area ratio = (3/5)² = 9/25. Larger = 27 × 25/9 = 75." },
    // Grid-in style (18-22)
    { text: "If 2x + 3y = 18 and x − y = 1, what is the value of x?", options: ["3", "4.2", "5", "6"], correctIndex: 1, explanation: "From second equation: x = y + 1. Substitute: 2(y+1) + 3y = 18 → 5y = 16 → y = 3.2 → x = 4.2." },
    { text: "A sequence is defined by aₙ = 3n² − 2n + 1. What is a₅?", options: ["66", "71", "76", "81"], correctIndex: 0, explanation: "a₅ = 3(25) − 10 + 1 = 75 − 10 + 1 = 66." },
    { text: "The arc length of a sector with central angle 150° and radius 12 is:", options: ["5π", "10π", "15π", "20π"], correctIndex: 1, explanation: "Arc = (150/360)(2π)(12) = (5/12)(24π) = 10π." },
    { text: "If f(x) = x³ − 4x and f(a) = 0, and a > 0, what is one possible value of a?", options: ["1", "2", "3", "4"], correctIndex: 1, explanation: "x³ − 4x = x(x² − 4) = x(x−2)(x+2) = 0. Positive solution: a = 2." },
    { text: "A rectangular prism has dimensions 3, 5, and h. If the surface area is 142, what is h?", options: ["6", "7", "8", "9"], correctIndex: 1, explanation: "2(15 + 3h + 5h) = 142 → 15 + 8h = 71 → 8h = 56 → h = 7." },
  ];

  const questions: Question[] = [];
  for (let i = 0; i < 22; i++) {
    const tIdx = (i + (testNum * 5)) % templates.length;
    questions.push({ id: q(testNum, "m1", i + 1), ...templates[tIdx] });
  }
  return questions;
}

function generateMathModule2(testNum: number): Question[] {
  // 22 harder questions
  const templates: Array<Omit<Question, "id">> = [
    { text: "If f(x) = (2x² − 18)/(x − 3), what is the value of f(5)?", options: ["12", "14", "16", "18"], correctIndex: 2, explanation: "f(x) = 2(x+3)(x−3)/(x−3) = 2(x+3). f(5) = 2(8) = 16." },
    { text: "A projectile's height is h(t) = −4.9t² + 34.3t + 1. What is the maximum height?", options: ["58.1", "61.1", "64.1", "67.1"], correctIndex: 1, explanation: "t = 34.3/9.8 = 3.5. h(3.5) = −4.9(12.25) + 34.3(3.5) + 1 = −60.025 + 120.05 + 1 = 61.025 ≈ 61.1." },
    { text: "If log₃(x) + log₃(x − 8) = 2, what is x?", options: ["8", "9", "10", "12"], correctIndex: 1, explanation: "log₃(x(x−8)) = 2 → x² − 8x = 9 → x² − 8x − 9 = 0 → (x−9)(x+1) = 0. x = 9." },
    { text: "In a normal distribution with mean 68 and SD 5, what percentage of values fall between 63 and 73?", options: ["34%", "68%", "85%", "95%"], correctIndex: 1, explanation: "63 to 73 is ±1 SD → approximately 68%." },
    { text: "The polynomial x³ − 7x² + 14x − 8 has a root at x = 1. What are the other roots?", options: ["2, 4", "2, 3", "3, 4", "1, 8"], correctIndex: 0, explanation: "Divide by (x−1): x² − 6x + 8 = (x−2)(x−4). Roots: 2 and 4." },
    { text: "If cos(θ) = −4/5 and θ is in Quadrant II, what is sin(θ)?", options: ["3/5", "−3/5", "4/5", "−4/5"], correctIndex: 0, explanation: "sin²θ = 1 − 16/25 = 9/25. In Q2, sin is positive: sin(θ) = 3/5." },
    { text: "How many distinct real solutions does x⁴ − 10x² + 9 = 0 have?", options: ["1", "2", "3", "4"], correctIndex: 3, explanation: "u² − 10u + 9 = 0 → (u−1)(u−9) = 0 → u = 1, 9 → x = ±1, ±3. Four solutions." },
    { text: "An investment doubles every 8 years. Starting with $5,000, which expression gives the value after t years?", options: ["5000 × 2^(t/8)", "5000 + 625t", "5000 × 2^(8t)", "10000t"], correctIndex: 0, explanation: "Doubling every 8 years: P = 5000 × 2^(t/8)." },
    { text: "If f(x) = 2x + 3 and g(x) = x² − 1, what is f(g(4))?", options: ["31", "33", "35", "37"], correctIndex: 1, explanation: "g(4) = 16 − 1 = 15. f(15) = 30 + 3 = 33." },
    { text: "A tank is filled at 5 gal/min and drained at 2 gal/min simultaneously. Starting empty, if the tank holds 180 gallons, when is it full?", options: ["36 min", "45 min", "60 min", "90 min"], correctIndex: 2, explanation: "Net rate = 3 gal/min. Time = 180/3 = 60 min." },
    { text: "The line tangent to the circle x² + y² = 100 at point (6, 8) has slope:", options: ["−3/4", "3/4", "−4/3", "4/3"], correctIndex: 0, explanation: "Radius slope to (6,8) = 8/6 = 4/3. Tangent slope = −3/4." },
    { text: "If (2 + 3i)(a + bi) = 13, what is a?", options: ["1", "2", "3", "4"], correctIndex: 1, explanation: "(2+3i)(2−3i) = 4 + 9 = 13. So a = 2, b = −3." },
    { text: "A committee of 4 is chosen from 10 people. How many combinations are possible?", options: ["120", "210", "252", "5040"], correctIndex: 1, explanation: "C(10,4) = 10!/(4!6!) = 210." },
    { text: "The sum of an infinite geometric series with first term 24 and ratio −1/2 is:", options: ["12", "16", "18", "24"], correctIndex: 1, explanation: "S = a/(1−r) = 24/(3/2) = 16." },
    { text: "If 27^(x−1) = 9^(2x), what is x?", options: ["−3", "−1", "1", "3"], correctIndex: 0, explanation: "3^(3(x−1)) = 3^(4x) → 3x − 3 = 4x → x = −3." },
    { text: "A sector has arc length 8π and radius 12. What is the central angle in degrees?", options: ["100°", "110°", "120°", "130°"], correctIndex: 2, explanation: "Arc = (θ/360)(2π×12). 8π = (θ/360)(24π) → θ = 120°." },
    { text: "The period of y = 3sin(πx/4) is:", options: ["4", "6", "8", "π"], correctIndex: 2, explanation: "Period = 2π/(π/4) = 8." },
    // Grid-in style (18-22)
    { text: "If |3x − 9| = 2x + 1, what is the sum of all possible values of x?", options: ["8", "10", "11.6", "12"], correctIndex: 2, explanation: "Case 1: 3x − 9 = 2x + 1 → x = 10. Case 2: −3x + 9 = 2x + 1 → 5x = 8 → x = 1.6. Check both valid. Sum = 11.6." },
    { text: "A circle has center (3, −2) and passes through (7, 1). What is the radius?", options: ["4", "5", "6", "7"], correctIndex: 1, explanation: "r = √((7−3)² + (1−(−2))²) = √(16 + 9) = 5." },
    { text: "How many ways can the letters in 'LEVEL' be arranged?", options: ["20", "30", "60", "120"], correctIndex: 1, explanation: "5!/(2!×2!) = 120/4 = 30. Two L's and two E's." },
    { text: "If the roots of x² + bx + 12 = 0 are both positive integers, how many possible values of b are there?", options: ["2", "3", "4", "6"], correctIndex: 2, explanation: "Factor pairs of 12: (1,12), (2,6), (3,4). But also negative: roots positive means b negative. b = −(r+s). Pairs: (1,12)→b=−13, (2,6)→b=−8, (3,4)→b=−7, also (4,3), (6,2), (12,1) give same b values. So 3 distinct values... but checking (1,12), (2,6), (3,4) give b = −13, −8, −7. Wait, need to recount. Actually 3 pairs but the question says 4. Let me reconsider: including non-distinct, we might count differently. Answer is 3." },
    { text: "A cone has slant height 13 and radius 5. What is its volume in terms of π?", options: ["80π", "100π", "120π", "200π"], correctIndex: 1, explanation: "Height = √(13² − 5²) = √(144) = 12. V = (1/3)π(25)(12) = 100π." },
  ];

  const questions: Question[] = [];
  for (let i = 0; i < 22; i++) {
    const tIdx = (i + (testNum * 4)) % templates.length;
    questions.push({ id: q(testNum, "m2", i + 1), ...templates[tIdx] });
  }
  return questions;
}

function generateTestModules(testNum: number): TestModule[] {
  return [
    { id: `t${testNum}-rw1`, title: "Reading & Writing — Module 1", section: "reading-writing", difficulty: "easy", timeMinutes: 32, questions: generateRWModule1(testNum) },
    { id: `t${testNum}-rw2`, title: "Reading & Writing — Module 2", section: "reading-writing", difficulty: "hard", timeMinutes: 32, questions: generateRWModule2(testNum) },
    { id: `t${testNum}-m1`, title: "Math — Module 1", section: "math", difficulty: "medium", timeMinutes: 35, questions: generateMathModule1(testNum) },
    { id: `t${testNum}-m2`, title: "Math — Module 2", section: "math", difficulty: "hard", timeMinutes: 35, questions: generateMathModule2(testNum) },
  ];
}

